import{_ as a,o,c as e,ag as i}from"./chunks/framework.CTpQozEL.js";const p=JSON.parse('{"title":"검색 및 전송","description":"게이트웨이를 찾기 위한 노드 검색 및 전송 (Bonjour, Tailscale, SSH)","frontmatter":{"title":"검색 및 전송","description":"게이트웨이를 찾기 위한 노드 검색 및 전송 (Bonjour, Tailscale, SSH)"},"headers":[],"relativePath":"gateway/discovery.md","filePath":"gateway/discovery.md","lastUpdated":null}'),t={name:"gateway/discovery.md"};function c(r,l,d,n,s,S){return o(),e("div",null,[...l[0]||(l[0]=[i('<h1 id="검색-및-전송" tabindex="-1">검색 및 전송 <a class="header-anchor" href="#검색-및-전송" aria-label="Permalink to &quot;검색 및 전송&quot;">​</a></h1><p>OpenClaw에는 표면적으로는 유사해 보이는 두 가지 서로 다른 문제가 있습니다.</p><ol><li><strong>오퍼레이터 원격 제어</strong>: macOS 메뉴 바 앱이 다른 곳에서 실행 중인 게이트웨이를 제어합니다.</li><li><strong>노드 페어링</strong>: iOS/Android(및 미래의 노드)가 게이트웨이를 찾아 안전하게 페어링합니다.</li></ol><p>설계 목표는 모든 네트워크 검색/광고를 <strong>노드 게이트웨이</strong>(<code>openclaw gateway</code>)에 유지하고 클라이언트(mac 앱, iOS)는 소비자로 유지하는 것입니다.</p><h2 id="용어" tabindex="-1">용어 <a class="header-anchor" href="#용어" aria-label="Permalink to &quot;용어&quot;">​</a></h2><ul><li><strong>게이트웨이</strong>: 상태(세션, 페어링, 노드 레지스트리)를 소유하고 채널을 실행하는 단일 장시간 실행 게이트웨이 프로세스. 대부분의 설정에서는 호스트당 하나를 사용하며, 격리된 멀티 게이트웨이 설정도 가능합니다.</li><li><strong>게이트웨이 WS(컨트롤 플레인)</strong>: 기본적으로 <code>127.0.0.1:18789</code>의 WebSocket 엔드포인트. <code>gateway.bind</code>를 통해 LAN/tailnet에 바인딩할 수 있습니다.</li><li><strong>직접 WS 전송</strong>: LAN/tailnet을 대상으로 하는 게이트웨이 WS 엔드포인트(SSH 없음).</li><li><strong>SSH 전송(폴백)</strong>: <code>127.0.0.1:18789</code>를 SSH를 통해 포워딩하는 원격 제어.</li><li><strong>레거시 TCP 브리지(제거됨)</strong>: 이전 노드 전송(<a href="/openclaw-docs-ko/gateway/bridge-protocol">브리지 프로토콜</a> 참조). 더 이상 검색 광고되지 않으며 현재 빌드의 일부가 아닙니다.</li></ul><p>프로토콜 세부 사항:</p><ul><li><a href="/openclaw-docs-ko/gateway/protocol">게이트웨이 프로토콜</a></li><li><a href="/openclaw-docs-ko/gateway/bridge-protocol">브리지 프로토콜 (레거시)</a></li></ul><h2 id="직접-연결-과-ssh를-모두-유지하는-이유" tabindex="-1">&quot;직접 연결&quot;과 SSH를 모두 유지하는 이유 <a class="header-anchor" href="#직접-연결-과-ssh를-모두-유지하는-이유" aria-label="Permalink to &quot;&quot;직접 연결&quot;과 SSH를 모두 유지하는 이유&quot;">​</a></h2><ul><li><strong>직접 WS</strong>는 동일 네트워크 및 tailnet 내에서 최고의 UX를 제공합니다: <ul><li>Bonjour를 통한 LAN 자동 검색</li><li>게이트웨이가 소유하는 페어링 토큰 + ACL</li><li>쉘 액세스 불필요; 프로토콜 표면이 엄격하고 감사 가능하게 유지됩니다</li></ul></li><li><strong>SSH</strong>는 범용 폴백으로 남아 있습니다: <ul><li>SSH 액세스가 있는 곳이라면 어디서든 작동합니다 (관련 없는 네트워크에서도)</li><li>멀티캐스트/mDNS 문제에서 살아남습니다</li><li>SSH 외에는 새로운 인바운드 포트가 필요 없습니다</li></ul></li></ul><h2 id="검색-입력-클라이언트가-게이트웨이-위치를-파악하는-방법" tabindex="-1">검색 입력 (클라이언트가 게이트웨이 위치를 파악하는 방법) <a class="header-anchor" href="#검색-입력-클라이언트가-게이트웨이-위치를-파악하는-방법" aria-label="Permalink to &quot;검색 입력 (클라이언트가 게이트웨이 위치를 파악하는 방법)&quot;">​</a></h2><h3 id="_1-bonjour-dns-sd-검색" tabindex="-1">1) Bonjour / DNS-SD 검색 <a class="header-anchor" href="#_1-bonjour-dns-sd-검색" aria-label="Permalink to &quot;1) Bonjour / DNS-SD 검색&quot;">​</a></h3><p>멀티캐스트 Bonjour는 최선을 다하지만 네트워크를 넘지 않습니다. OpenClaw는 구성된 광역 DNS-SD 도메인을 통해 동일한 게이트웨이 비콘을 탐색할 수 있으므로 검색은 다음을 커버할 수 있습니다:</p><ul><li>동일 LAN의 <code>local.</code></li><li>크로스 네트워크 검색을 위한 구성된 유니캐스트 DNS-SD 도메인</li></ul><p>목표 방향:</p><ul><li><strong>게이트웨이</strong>는 Bonjour를 통해 WS 엔드포인트를 광고합니다.</li><li>클라이언트는 탐색하고 &quot;게이트웨이 선택&quot; 목록을 표시한 다음, 선택된 엔드포인트를 저장합니다.</li></ul><p>문제 해결 및 비콘 세부 사항: <a href="/openclaw-docs-ko/gateway/bonjour">Bonjour</a>.</p><h4 id="서비스-비콘-세부-사항" tabindex="-1">서비스 비콘 세부 사항 <a class="header-anchor" href="#서비스-비콘-세부-사항" aria-label="Permalink to &quot;서비스 비콘 세부 사항&quot;">​</a></h4><ul><li>서비스 유형: <ul><li><code>_openclaw-gw._tcp</code> (게이트웨이 전송 비콘)</li></ul></li><li>TXT 키 (비시크릿): <ul><li><code>role=gateway</code></li><li><code>transport=gateway</code></li><li><code>displayName=&lt;친숙한 이름&gt;</code> (오퍼레이터 구성 표시 이름)</li><li><code>lanHost=&amp;lt;hostname&amp;gt;.local</code></li><li><code>gatewayPort=18789</code> (게이트웨이 WS + HTTP)</li><li><code>gatewayTls=1</code> (TLS 활성화 시에만)</li><li><code>gatewayTlsSha256=&amp;lt;sha256&amp;gt;</code> (TLS가 활성화되고 지문이 사용 가능한 경우에만)</li><li><code>canvasPort=&amp;lt;port&amp;gt;</code> (캔버스 호스트 포트; 현재 캔버스 호스트가 활성화된 경우 <code>gatewayPort</code>와 동일)</li><li><code>tailnetDns=&amp;lt;magicdns&amp;gt;</code> (선택적 힌트; Tailscale 사용 가능 시 자동 감지)</li><li><code>sshPort=&amp;lt;port&amp;gt;</code> (mDNS 전체 모드 전용; 광역 DNS-SD는 생략할 수 있으며, 이 경우 SSH 기본값은 <code>22</code>)</li><li><code>cliPath=&amp;lt;path&amp;gt;</code> (mDNS 전체 모드 전용; 광역 DNS-SD는 원격 설치 힌트로 계속 기록)</li></ul></li></ul><p>보안 참고 사항:</p><ul><li>Bonjour/mDNS TXT 레코드는 <strong>인증되지 않습니다</strong>. 클라이언트는 TXT 값을 UX 힌트로만 취급해야 합니다.</li><li>라우팅(호스트/포트)은 TXT에서 제공하는 <code>lanHost</code>, <code>tailnetDns</code>, 또는 <code>gatewayPort</code>보다 <strong>해결된 서비스 엔드포인트</strong>(SRV + A/AAAA)를 우선해야 합니다.</li><li>TLS 핀닝은 광고된 <code>gatewayTlsSha256</code>이 이전에 저장된 핀을 재정의하도록 허용해서는 안 됩니다.</li><li>iOS/Android 노드는 선택된 경로가 보안/TLS 기반인 경우 처음 핀을 저장하기 전에 명시적인 &quot;이 지문을 신뢰&quot; 확인이 필요합니다 (대역 외 검증).</li></ul><p>비활성화/재정의:</p><ul><li><code>OPENCLAW_DISABLE_BONJOUR=1</code>은 광고를 비활성화합니다.</li><li><code>~/.openclaw/openclaw.json</code>의 <code>gateway.bind</code>는 게이트웨이 바인딩 모드를 제어합니다.</li><li><code>OPENCLAW_SSH_PORT</code>는 <code>sshPort</code>가 내보내질 때 광고되는 SSH 포트를 재정의합니다.</li><li><code>OPENCLAW_TAILNET_DNS</code>는 <code>tailnetDns</code> 힌트(MagicDNS)를 게시합니다.</li><li><code>OPENCLAW_CLI_PATH</code>는 광고된 CLI 경로를 재정의합니다.</li></ul><h3 id="_2-tailnet-크로스-네트워크" tabindex="-1">2) Tailnet (크로스 네트워크) <a class="header-anchor" href="#_2-tailnet-크로스-네트워크" aria-label="Permalink to &quot;2) Tailnet (크로스 네트워크)&quot;">​</a></h3><p>런던/비엔나 스타일 설정의 경우 Bonjour는 도움이 되지 않습니다. 권장 &quot;직접&quot; 대상은:</p><ul><li>Tailscale MagicDNS 이름(선호) 또는 안정적인 tailnet IP.</li></ul><p>게이트웨이가 Tailscale 아래에서 실행되고 있음을 감지할 수 있는 경우, 클라이언트(광역 비콘 포함)를 위한 선택적 힌트로 <code>tailnetDns</code>를 게시합니다.</p><p>macOS 앱은 이제 게이트웨이 검색에서 원시 Tailscale IP보다 MagicDNS 이름을 우선합니다. 이는 tailnet IP가 변경될 때(예: 노드 재시작 또는 CGNAT 재할당 후) MagicDNS 이름이 자동으로 현재 IP로 해석되므로 안정성이 향상됩니다.</p><p>모바일 노드 페어링의 경우, 검색 힌트는 tailnet/공용 경로에서 전송 보안을 완화하지 않습니다:</p><ul><li>iOS/Android는 보안된 첫 번째 tailnet/공용 연결 경로(<code>wss://</code> 또는 Tailscale Serve/Funnel)를 여전히 필요로 합니다.</li><li>발견된 원시 tailnet IP는 라우팅 힌트이지, 일반 텍스트 원격 <code>ws://</code>를 사용할 권한이 아닙니다.</li><li>개인 LAN 직접 연결 <code>ws://</code>는 지원됩니다.</li><li>모바일 노드를 위한 가장 단순한 Tailscale 경로를 원한다면, 검색과 설정 코드가 모두 동일한 보안 MagicDNS 엔드포인트로 해결되도록 Tailscale Serve를 사용하십시오.</li></ul><h3 id="_3-수동-ssh-대상" tabindex="-1">3) 수동 / SSH 대상 <a class="header-anchor" href="#_3-수동-ssh-대상" aria-label="Permalink to &quot;3) 수동 / SSH 대상&quot;">​</a></h3><p>직접 경로가 없는 경우(또는 직접 연결이 비활성화된 경우), 클라이언트는 루프백 게이트웨이 포트를 포워딩하여 SSH를 통해 항상 연결할 수 있습니다.</p><p><a href="/openclaw-docs-ko/gateway/remote">원격 액세스</a> 참조.</p><h2 id="전송-선택-클라이언트-정책" tabindex="-1">전송 선택 (클라이언트 정책) <a class="header-anchor" href="#전송-선택-클라이언트-정책" aria-label="Permalink to &quot;전송 선택 (클라이언트 정책)&quot;">​</a></h2><p>권장 클라이언트 동작:</p><ol><li>페어링된 직접 엔드포인트가 구성되어 있고 연결 가능하면 그것을 사용합니다.</li><li>그렇지 않으면, 검색이 <code>local.</code> 또는 구성된 광역 도메인에서 게이트웨이를 찾으면, 원탭 &quot;이 게이트웨이 사용&quot; 선택을 제공하고 직접 엔드포인트로 저장합니다.</li><li>그렇지 않으면, tailnet DNS/IP가 구성되어 있으면 직접 연결을 시도합니다. tailnet/공용 경로의 모바일 노드의 경우, 직접은 일반 텍스트 원격 <code>ws://</code>가 아닌 보안 엔드포인트를 의미합니다.</li><li>그렇지 않으면 SSH로 폴백합니다.</li></ol><h2 id="페어링-인증-직접-전송" tabindex="-1">페어링 + 인증 (직접 전송) <a class="header-anchor" href="#페어링-인증-직접-전송" aria-label="Permalink to &quot;페어링 + 인증 (직접 전송)&quot;">​</a></h2><p>게이트웨이는 노드/클라이언트 승인의 신뢰 소스입니다.</p><ul><li>페어링 요청은 게이트웨이에서 생성/승인/거부됩니다 (<a href="/openclaw-docs-ko/gateway/pairing">게이트웨이 페어링</a> 참조).</li><li>게이트웨이는 다음을 강제합니다: <ul><li>인증 (토큰 / 키페어)</li><li>범위/ACL (게이트웨이는 모든 메서드에 대한 원시 프록시가 아닙니다)</li><li>속도 제한</li></ul></li></ul><h2 id="컴포넌트별-책임" tabindex="-1">컴포넌트별 책임 <a class="header-anchor" href="#컴포넌트별-책임" aria-label="Permalink to &quot;컴포넌트별 책임&quot;">​</a></h2><ul><li><strong>게이트웨이</strong>: 검색 비콘을 광고하고, 페어링 결정을 소유하며, WS 엔드포인트를 호스팅합니다.</li><li><strong>macOS 앱</strong>: 게이트웨이 선택을 돕고, 페어링 프롬프트를 표시하며, SSH는 폴백으로만 사용합니다.</li><li><strong>iOS/Android 노드</strong>: Bonjour를 편의 수단으로 탐색하고 페어링된 게이트웨이 WS에 연결합니다.</li></ul>',41)])])}const h=a(t,[["render",c]]);export{p as __pageData,h as default};
